import{_ as l,o as i,c as e,ae as t}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"向量数据库科普与选型：从 Embedding 到 HNSW","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/vector-database.md","filePath":"ai-tutorial/vector-database.md"}'),r={name:"ai-tutorial/vector-database.md"};function s(n,a,o,h,p,d){return i(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="向量数据库科普与选型-从-embedding-到-hnsw" tabindex="-1">向量数据库科普与选型：从 Embedding 到 HNSW <a class="header-anchor" href="#向量数据库科普与选型-从-embedding-到-hnsw" aria-label="Permalink to &quot;向量数据库科普与选型：从 Embedding 到 HNSW&quot;">​</a></h1><blockquote><p>向量数据库这些年常被讲得很神秘，好像只要把文档往里一丢，语义检索就会自动变聪明。 现实当然没这么省心。它确实是 RAG 里非常重要的一环，但如果不理解它到底存了什么、查了什么、为什么快、又为什么会贵，你在选型、调参和容量规划上很容易一路踩坑。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>向量到底是什么，为什么可以支持语义检索</li><li>ANN 为何是向量检索系统的核心</li><li>HNSW 为什么流行，它的代价又是什么</li><li>向量数据库该如何放到 RAG 系统里理解</li></ul></div><h2 id="_1-什么是向量" tabindex="-1">1. 什么是向量 <a class="header-anchor" href="#_1-什么是向量" aria-label="Permalink to &quot;1. 什么是向量&quot;">​</a></h2><p>当一段文本被 Embedding 模型处理后，它会被映射成一串高维数值。你可以把它理解成“语义坐标”：</p><ul><li>内容相近的文本，通常在向量空间里更接近</li><li>内容差异大的文本，通常更远</li></ul><p>这也是向量检索能做语义匹配的基础。</p><p>它和传统关键词检索的最大差别是：</p><ul><li>关键词检索看字面是否匹配</li><li>向量检索看语义是否相近</li></ul><h2 id="_2-为什么不能直接暴力全量比对" tabindex="-1">2. 为什么不能直接暴力全量比对 <a class="header-anchor" href="#_2-为什么不能直接暴力全量比对" aria-label="Permalink to &quot;2. 为什么不能直接暴力全量比对&quot;">​</a></h2><p>理论上，用户问题向量生成后，可以和所有文档向量逐个比较相似度，然后选 Top K。</p><p>但当数据规模变大，这种全量扫描会迅速失去可用性。于是工程上需要近似最近邻（ANN）方法，在速度和精度之间做平衡。</p><h2 id="_3-ann-向量检索系统真正的核心" tabindex="-1">3. ANN：向量检索系统真正的核心 <a class="header-anchor" href="#_3-ann-向量检索系统真正的核心" aria-label="Permalink to &quot;3. ANN：向量检索系统真正的核心&quot;">​</a></h2><p>ANN 的目标不是保证数学上绝对最优，而是在可接受时间内找到“足够好的近邻”。</p><p>这也是向量数据库区别于“只会存向量”的关键之处：它不只是存储，更重要的是建立高效索引和近似搜索机制。</p><h2 id="_4-hnsw-为什么这么常见" tabindex="-1">4. HNSW 为什么这么常见 <a class="header-anchor" href="#_4-hnsw-为什么这么常见" aria-label="Permalink to &quot;4. HNSW 为什么这么常见&quot;">​</a></h2><p>HNSW（Hierarchical Navigable Small World）之所以流行，原因通常有三点：</p><ul><li>检索速度快</li><li>召回率表现好</li><li>在很多通用场景里效果稳定</li></ul><p>它的直觉可以理解为：通过多层图结构，把“从远到近逼近目标”的搜索过程组织起来，让系统不必遍历所有节点。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L3[&quot;高层稀疏图&quot;] --&gt; L2[&quot;中层图&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L2 --&gt; L1[&quot;底层密集图&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;查询向量&quot;] --&gt; L3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L1 --&gt; R[&quot;近邻结果&quot;]</span></span></code></pre></div><p>搜索时，系统会先在高层快速靠近目标区域，再逐层下钻到更细粒度的邻域。</p><h2 id="_5-hnsw-的代价-不是没有代价的高性能" tabindex="-1">5. HNSW 的代价：不是没有代价的高性能 <a class="header-anchor" href="#_5-hnsw-的代价-不是没有代价的高性能" aria-label="Permalink to &quot;5. HNSW 的代价：不是没有代价的高性能&quot;">​</a></h2><p>HNSW 的常见代价包括：</p><ul><li>索引内存占用高</li><li>构建和维护索引需要成本</li><li>在超大规模数据场景下，资源规划要谨慎</li></ul><p>所以它并不是“永远最优解”，而是一个在速度和质量之间很平衡的默认选项。</p><h2 id="_6-选型时真正该看什么" tabindex="-1">6. 选型时真正该看什么 <a class="header-anchor" href="#_6-选型时真正该看什么" aria-label="Permalink to &quot;6. 选型时真正该看什么&quot;">​</a></h2><p>讨论向量数据库时，别只问“支不支持 HNSW”。更重要的是：</p><ul><li>数据规模多大</li><li>查询延迟要求多高</li><li>是否需要过滤条件</li><li>是否需要和关键词检索混合</li><li>是否需要分片、持久化和运维能力</li></ul><p>因为对 RAG 来说，向量库不是单独存在的，而是检索链路中的一环。</p><h2 id="_7-向量检索不是对关键词检索的完全替代" tabindex="-1">7. 向量检索不是对关键词检索的完全替代 <a class="header-anchor" href="#_7-向量检索不是对关键词检索的完全替代" aria-label="Permalink to &quot;7. 向量检索不是对关键词检索的完全替代&quot;">​</a></h2><p>向量检索很擅长找“意思相近”，但对下面这些内容未必天然占优：</p><ul><li>编号</li><li>特定术语</li><li>SKU、设备 ID</li><li>法条编号</li></ul><p>所以企业场景里，常见做法不是“只留向量检索”，而是把它和关键词检索结合起来，形成混合检索。</p><h2 id="_8-在-rag-里应该怎么理解向量数据库" tabindex="-1">8. 在 RAG 里应该怎么理解向量数据库 <a class="header-anchor" href="#_8-在-rag-里应该怎么理解向量数据库" aria-label="Permalink to &quot;8. 在 RAG 里应该怎么理解向量数据库&quot;">​</a></h2><p>对 RAG 系统来说，向量数据库的职责主要是：</p><ul><li>存放向量化后的知识片段</li><li>提供相似度召回能力</li><li>配合过滤和排序产生候选集合</li></ul><p>它并不负责：</p><ul><li>文档解析</li><li>答案生成</li><li>最终事实校验</li></ul><p>把它看成“RAG 的核心组件之一”，会比看成“RAG 的全部答案”更准确。</p><h2 id="_9-小结" tabindex="-1">9. 小结 <a class="header-anchor" href="#_9-小结" aria-label="Permalink to &quot;9. 小结&quot;">​</a></h2><p>向量数据库之所以重要，不是因为“向量”这个概念神秘，而是因为它让语义检索在工程上可行。真正值得关注的是：</p><ul><li>Embedding 如何表达语义相近</li><li>ANN 如何在效率和精度间取舍</li><li>HNSW 为什么常用、代价是什么</li><li>向量检索如何与关键词检索共同构成完整 RAG 链路</li></ul><p>理解这些之后，再做选型、调参与容量规划，会比只看产品宣传稳得多。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/1603.09320" target="_blank" rel="noreferrer">Hierarchical Navigable Small World Graphs</a></li><li><a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks</a></li><li>延伸阅读：<a href="./rag-deep-dive.html">深入剖析 RAG</a></li></ul>`,45)])])}const b=l(r,[["render",s]]);export{c as __pageData,b as default};
